import { NgModule } from '@angular/core';
import { Routes, RouterModule } from '@angular/router';

const routes: Routes = [
  {
    path: 'components',
    loadChildren: () =>
      import('./my-components/my-components.module').then(
        (m) => m.MyComponentsModule
      ),
    // data: {
    //   seo: {
    //     title: 'Component Page | Dynamic Title and Meta Tags Demo',
    //     metaTags: [
    //       { name: 'description', content: 'Component description' },
    //       { property: 'og:title', content: 'Component title' },
    //       { proprety: 'og:description', content: 'Component description' },
    //       { name: 'twitter:card', content: 'summary_large_image' },
    //     ],
    //   },
    // },
  },
  {
    path: 'home',
    loadChildren: () => import('./home/home.module').then((m) => m.HomeModule),
    // data: {
    //   seo: {
    //     title: 'Home Page | Dynamic Title and Meta Tags Demo',
    //     metaTags: [
    //       { name: 'description', content: 'Home description' },
    //       { property: 'og:title', content: 'Home title' },
    //       { proprety: 'og:description', content: 'Home description' },
    //       { name: 'twitter:card', content: 'summary_large_image' },
    //     ],
    //   },
    // },
  },
  {
    path: 'users',
    loadChildren: () => import('./user/user.module').then((m) => m.UserModule),
  },
];

@NgModule({
  imports: [RouterModule.forRoot(routes, {
    initialNavigation: 'enabled'
})],
  exports: [RouterModule],
})
export class AppRoutingModule {}
